    private function downloadCover(string $url, string $slug): ?string
    {
        if (empty($url)) return null;

        $url = preg_replace('/-\d+x\d+\.(webp|jpg|jpeg|png)$/', '-600x600.$1', $url);
        $ext  = pathinfo(parse_url($url, PHP_URL_PATH), PATHINFO_EXTENSION) ?: 'webp';
        $name = pathinfo(parse_url($url, PHP_URL_PATH), PATHINFO_FILENAME);
        $name = preg_replace('/-\d+x\d+$/', '', $name);
        $path = "blog/{$slug}.{$ext}";

        if (Storage::disk('public')->exists($path)) {
            return Storage::disk('public')->url($path);
        }

        try {
            $response = Http::timeout(20)
                ->withHeaders(['User-Agent' => 'Mozilla/5.0', 'Referer' => 'https://sota.store/'])
                ->get($url);

            if ($response->successful() && str_starts_with($response->header('Content-Type') ?? '', 'image/')) {
                Storage::disk('public')->put($path, $response->body());
                return Storage::disk('public')->url($path);
            }
        } catch (\Throwable) {}

        return $url;
    }
